  "get_firewall_info": {
    "description": "Retrieves the current state of the firewall, including operational status, rule list, default policy, and logging status.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "status": "DEGRADED",
      "rules": [
        {
          "id": "rule-101",
          "priority": 10,
          "source": "10.0.1.0/24",
          "destination": "ANY",
          "port": "ANY",
          "protocol": "ANY",
          "action": "ALLOW"
        }
      ],
      "default_policy": "DENY",
      "logging_enabled": true
