    "parameters": {
      "type": "object",
      "properties": {
        "priority": {
          "type": "integer",
          "description": "The priority of the rule (lower numbers usually indicate higher precedence)."
        },
        "source": {
          "type": "string",
          "description": "Source IP or CIDR block."
        },
        "destination": {
          "type": "string",
          "description": "Destination IP or CIDR block."
        },
        "port": {
          "type": "string",
          "description": "Target port (e.g., '5432') or 'ANY'."
        },
        "protocol": {
          "type": "string",
          "description": "Protocol (e.g., 'TCP', 'UDP', 'ICMP')."
        },
        "action": {
          "type": "string",
          "enum": [
            "ALLOW",
            "DENY"
          ],
          "description": "The action to take when traffic matches the rule."
        }
      },
      "required": [
        "priority",
        "source",
        "destination",
        "port",
        "protocol",
        "action"
      ]
    },
    "example_output": {
