      "rule_id": "rule-202"
    }
  },
  "delete_rule": {
    "description": "Removes an existing rule from the firewall to free up TCAM resources or modify policy logic.",
    "parameters": {
      "type": "object",
      "properties": {
        "rule_id": {
          "type": "string",
          "description": "The unique identifier of the rule to be removed."
        }
