      "required": [
        "rule_id"
      ]
    },
    "example_output": {
      "success": true,
      "removed_id": "rule-101"
    }
  },
  "update_default_policy": {
    "description": "Changes the global default action for traffic that does not match any specific rule.",
    "parameters": {
      "type": "object",
      "properties": {
        "action": {
          "type": "string",
          "enum": [
            "ALLOW",
            "DENY"
          ],
          "description": "The new default policy action."
        }
      },
      "required": [
        "action"
      ]
    },
    "example_output": {
      "success": true,
      "new_default": "DENY"
    }
  }
}
